// src/pages/dashboard/ContentDashboard.js
import React from "react";
import Layout from "../../components/layout/Layout";
import Navbar from "../../components/Navbar";
import Sidebar from "../../components/Sidebar";
import { Bar } from "react-chartjs-2";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";

ChartJS.register(CategoryScale, LinearScale, BarElement, Title, Tooltip, Legend);

function ContentDashboard() {
  // Example chart for content uploads
  const chartData = {
    labels: ["Week 1", "Week 2", "Week 3", "Week 4"],
    datasets: [
      {
        label: "New Content Uploaded",
        data: [5, 8, 3, 6],
        backgroundColor: "#059669",
      },
      {
        label: "Content Updates",
        data: [2, 4, 3, 5],
        backgroundColor: "#10b981",
      },
    ],
  };

  const chartOptions = {
    responsive: true,
    plugins: {
      legend: { position: "top" },
      title: { display: true, text: "Content Upload Activity" },
    },
  };

  return (
    <Layout pageTitle="Content Creator Dashboard - NexaLearn LMS">
      <Navbar />
      <div className="d-flex" style={{ minHeight: "80vh" }}>
        <Sidebar />
        <div className="flex-grow-1 p-4">
          <h1 style={{ color: "#059669", fontWeight: "700", marginBottom: "25px" }}>
            Content Creator Dashboard
          </h1>

          {/* Quick Info Cards */}
          <div className="row g-4 mb-4">
            <div className="col-md-4">
              <div className="card shadow-sm p-3" style={{ borderLeft: "5px solid #059669", borderRadius: "10px" }}>
                <h5 className="card-title text-secondary">Total Content</h5>
                <p className="display-5 fw-bold">24</p>
                <p className="text-success">+3 this week</p>
              </div>
            </div>

            <div className="col-md-4">
              <div className="card shadow-sm p-3" style={{ borderLeft: "5px solid #10b981", borderRadius: "10px" }}>
                <h5 className="card-title text-secondary">Drafts</h5>
                <p className="display-5 fw-bold">5</p>
                <p className="text-warning">Pending review</p>
              </div>
            </div>

            <div className="col-md-4">
              <div className="card shadow-sm p-3" style={{ borderLeft: "5px solid #14b8a6", borderRadius: "10px" }}>
                <h5 className="card-title text-secondary">Published</h5>
                <p className="display-5 fw-bold">19</p>
                <p className="text-success">+2 this week</p>
              </div>
            </div>
          </div>

          {/* Chart Section */}
          <div className="card shadow-sm p-4 mb-4" style={{ borderRadius: "12px" }}>
            <h5 style={{ marginBottom: "20px", fontWeight: "600" }}>Content Activity Overview</h5>
            <Bar data={chartData} options={chartOptions} />
          </div>

          {/* Action Panel */}
          <div className="card shadow-sm p-4" style={{ borderRadius: "12px", backgroundColor: "#f0fdf4" }}>
            <h5 style={{ marginBottom: "15px", fontWeight: "600" }}>Create and Manage Content</h5>
            <p style={{ color: "#065f46", lineHeight: "1.6" }}>
              Upload new course materials, update existing content, and track content performance. Ensure educational quality and student engagement.
            </p>
            <button
              style={{
                backgroundColor: "#059669",
                color: "#fff",
                border: "none",
                padding: "12px 20px",
                borderRadius: "6px",
                fontWeight: "600",
                cursor: "pointer",
                transition: "background-color 0.3s ease",
              }}
              onMouseOver={(e) => (e.target.style.backgroundColor = "#047857")}
              onMouseOut={(e) => (e.target.style.backgroundColor = "#059669")}
            >
              Create New Content
            </button>
          </div>
        </div>
      </div>
    </Layout>
  );
}

export default ContentDashboard;
